import React, { useState, useEffect } from 'react';
import './CommandeForm.css';

const CommandeForm = ({ selectedCommande, onSuccess, onCancel }) => {
  const [formData, setFormData] = useState({
    idCOM: '',
    codeCli: '',
    codeArt: '',
    dateCom: '',
    QteCom: ''
  });

  const [factureVisible, setFactureVisible] = useState(false);
  const [factureData, setFactureData] = useState(null);
  const [message, setMessage] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    if (selectedCommande) {
      setFormData(selectedCommande);
      setFactureVisible(false); // réinitialise l'affichage de facture si sélection change
    } else {
      resetForm();
    }
  }, [selectedCommande]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const resetForm = () => {
    setFormData({
      idCOM: '',
      codeCli: '',
      codeArt: '',
      dateCom: '',
      QteCom: ''
    });
    setFactureVisible(false);
    setFactureData(null);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const method = formData.idCOM ? 'PUT' : 'POST';
    const url = formData.idCOM
      ? `http://localhost:3001/commandes/${formData.idCOM}`
      : 'http://localhost:3001/commandes';

    try {
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });

      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      setMessage(formData.idCOM ? 'Commande modifiée avec succès.' : 'Commande ajoutée avec succès.');
      setError('');
      resetForm();
      if (onSuccess) onSuccess();
    } catch (err) {
      setError(err.message);
      setMessage('');
    }
  };

  const handleDelete = async () => {
    const confirmDelete = window.confirm('Supprimer cette commande ?');
    if (!confirmDelete) return;

    try {
      const res = await fetch(`http://localhost:3001/commandes/${formData.idCOM}`, {
        method: 'DELETE'
      });

      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      setMessage('Commande supprimée avec succès.');
      setError('');
      resetForm();
      if (onSuccess) onSuccess();
    } catch (err) {
      setError(err.message);
      setMessage('');
    }
  };

  const handleVoirFacture = () => {
    console.log("Voir facture cliqué");
    setFactureData({ ...formData });
    setFactureVisible(true);
  };

  return (
    <div>
      <form onSubmit={handleSubmit} className="commande-form">
        <input
          name="idCOM"
          placeholder="ID Commande"
          value={formData.idCOM}
          onChange={handleChange}
        />
        <input
          name="codeCli"
          placeholder="Code Client"
          value={formData.codeCli}
          onChange={handleChange}
          required
        />
        <input
          name="codeArt"
          placeholder="Code Article"
          value={formData.codeArt}
          onChange={handleChange}
          required
        />
        <input
          type="date"
          name="dateCom"
          placeholder="Date de commande"
          value={formData.dateCom}
          onChange={handleChange}
          required
        />
        <input
          type="number"
          name="QteCom"
          placeholder="Quantité"
          value={formData.QteCom}
          onChange={handleChange}
          required
        />

        <button type="submit">
          {formData.idCOM ? 'Modifier' : 'Ajouter'}
        </button>

        {formData.idCOM && (
          <>
            <button type="button" onClick={handleDelete}>Supprimer</button>
            <button type="button" onClick={handleVoirFacture}>Voir facture</button>
            <button type="button" onClick={onCancel}>Annuler</button>
          </>
        )}

        {message && <div className="success">{message}</div>}
        {error && <div className="error">{error}</div>}
      </form>

      {factureVisible && factureData && (
        <div className="facture-box">
          <h3>🧾 Facture Commande #{factureData.idCOM}</h3>
          <p><strong>Client :</strong> {factureData.codeCli}</p>
          <p><strong>Article :</strong> {factureData.codeArt}</p>
          <p><strong>Date :</strong> {factureData.dateCom}</p>
          <p><strong>Quantité :</strong> {factureData.QteCom}</p>
        </div>
      )}
    </div>
  );
};

export default CommandeForm;
